SELECT p.id, p.public_id::text AS publicKey, p.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.code AS hospitalCode, h.name AS hospitalName, p.patient_uid AS patientCode, p.first_name AS firstName, p.last_name AS lastName, p.phone_number AS phoneNumber, p.gender, p.date_of_birth AS dateOfBirth FROM patients p INNER JOIN hospitals h ON h.id = p.hospital_id WHERE p.is_active = 1
AND p.hospital_id = #{hospitalId}
AND p.id < #{filter.lastPatientId}
AND ( LOWER(p.patient_uid) = LOWER(#{filter.searchText}) OR LOWER(COALESCE(p.phone_number, '')) = LOWER(#{filter.searchText}) OR p.patient_uid ILIKE '%' || #{filter.searchText} || '%' OR p.first_name ILIKE '%' || #{filter.searchText} || '%' OR p.last_name ILIKE '%' || #{filter.searchText} || '%' OR TRIM(CONCAT(COALESCE(p.first_name, ''), ' ', COALESCE(p.last_name, ''))) ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(p.phone_number, '') ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(h.name, '') ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(h.code, '') ILIKE '%' || #{filter.searchText} || '%' )
AND LOWER(p.patient_uid) = LOWER(#{filter.patientCode})
AND p.first_name ILIKE '%' || #{filter.firstName} || '%'
AND p.last_name ILIKE '%' || #{filter.lastName} || '%'
AND LOWER(COALESCE(p.phone_number, '')) = LOWER(#{filter.phoneNumber})
AND p.gender = #{filter.gender}
ORDER BY p.id DESC
LIMIT #{filter.rowsPerPage}
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}

SELECT p.id, p.public_id::text AS publicKey, p.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.code AS hospitalCode, h.name AS hospitalName, p.patient_uid AS patientCode, p.first_name AS firstName, p.last_name AS lastName, p.phone_number AS phoneNumber, p.gender, p.date_of_birth AS dateOfBirth FROM patients p INNER JOIN hospitals h ON h.id = p.hospital_id WHERE p.id = #{id} AND p.is_active = 1
AND p.hospital_id = #{hospitalId}
LIMIT 1
